const rawText = $input.first().json.output;

if (!rawText || rawText.trim() === "") {
  return [{ json: buildErrorResult() }];
}

let aiData;
try {
  let jsonData = JSON.parse(rawText);
  if (Array.isArray(jsonData)) {
    aiData = jsonData[0];
    if (aiData.output) {
      aiData = JSON.parse(aiData.output);
    }
  } else if (jsonData.output) {
    aiData = JSON.parse(jsonData.output);
  } else {
    aiData = jsonData;
  }
} 
catch (err) {
  return [{ json: buildErrorResult(err.message) }];
}

function safeString(val) {
  if (val === null || val === undefined) return 'Unknown';
  if (Array.isArray(val)) return val.join(', '); 
  return val; 
}

let companyData = buildBaseResult(aiData);
let { errors, status } = validateCompanyData(companyData);

let result = buildResult(companyData, errors, status);

return [{
  json: result
}];

function buildErrorResult(errorMessage) {
  return {
    name: 'Unknown',
    industry: 'Error parsing data',
    tags: 'Error parsing data',
    keyProducts: 'Error parsing data',
    profile: 'Error parsing data',
    competitors: 'Error parsing data',
    website: 'Error parsing data',
    companySize: 'Error parsing data',
    lastUpdate: new Date().toISOString().split('T'),
    errorMessage: errorMessage,
    isValid: "invalidData",
    errors: ["ERROR PARSING DATA"]
  };
}

function buildBaseResult(aiData) {
  return {
    name: aiData.name || 'Unknown',
    industry: aiData.industry || 'Unknown',
    tags: safeString(aiData.tags) || 'Unknown',
    keyProducts: safeString(aiData.keyProducts) || 'Unknown',
    profile: aiData.profile || 'Unknown',
    competitors: safeString(aiData.competitors) || 'Unknown',
    website: aiData.website || 'Unknown',
    companySize: aiData.companySize || 'Unknown',
    lastUpdate: new Date().toISOString()
  }
}

function buildResult(companyData, errors, status) {
  return {
    ...companyData,
    errors: errors,
    isValid: status
  }
}

function validateCompanyData(companyData) {
  let errors = [];
  let status;

  if (companyData.name === "Unknown") errors.push(`INVALID name`);
  if (companyData.industry === "Unknown") errors.push(`INVALID industry`);
  if (companyData.profile === "Unknown") errors.push(`INVALID profile`);

  errors.push(
    ...[['competitors', companyData.competitors], ['tags', companyData.tags], ['keyProducts', companyData.keyProducts], ['website', companyData.website], ['companySize', companyData.companySize]]
      .filter(([_, val]) => val === "Unknown")
      .map(([field]) => `INVALID ${field}`)
  );
  if (
    companyData.name === "Unknown" &&
    companyData.industry === "Unknown" &&
    companyData.profile === "Unknown" &&
    companyData.website === "Unknown" &&
    companyData.keyProducts === "Unknown"
  ) {
    status = "invalidData"
  } else if (
    companyData.name === "Unknown" || 
    companyData.industry === "Unknown" || 
    companyData.profile === "Unknown" ||
    companyData.website === "Unknown"
  ) {
    status = "criticalDataIsMissing";
  } else if (errors.length > 0) {
    status = "averagValueDataMissing";
  } else {
    status = "validData";
  }
  return { errors, status };
}
